const TABLES: Record<string, ReadonlyArray<Row>> = {
  MES: MES_DAILY_CLOSES, MYM: MYM_DAILY_CLOSES, MCL: MCL_DAILY_CLOSES, MGC: MGC_DAILY_CLOSES,
  RTY: RTY_DAILY_CLOSES,
};

/** Latest close on or before isoDate for a non-MNQ asset (null if before history). */
export function assetTableCloseForDate(asset: string, isoDate: string | null): number | null {
  if (!isoDate) return null;
  const arr = TABLES[asset];
  if (!arr || arr.length === 0) return null;
  if (isoDate < arr[0][0]) return null;
  if (isoDate >= arr[arr.length - 1][0]) return arr[arr.length - 1][1];
  let lo = 0, hi = arr.length - 1, ans = 0;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    if (arr[mid][0] <= isoDate) { ans = mid; lo = mid + 1; } else { hi = mid - 1; }
  }
  return arr[ans][1];
}

